using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var log = BinaryLog.ReadBuild("/tmp/sv-fd82207675f14ae0b53fd6d947d143b9/build.binlog");

// Get source file content embedded in binlog
Console.WriteLine("=== EMBEDDED SOURCE FILES ===");
var sourceFiles = log.FindChildrenRecursive<SourceFileLine>();
Console.WriteLine($"SourceFileLine count: {sourceFiles.Count}");

// Try to find the UserService.cs content via compiler command line
Console.WriteLine("\n=== CSC TASKS ===");
var tasks = log.FindChildrenRecursive<Task>();
foreach (var t in tasks)
{
    if (t.Name == "Csc")
    {
        Console.WriteLine($"  Csc in project: {t.Parent?.Parent}");
        var cmdLine = t.FindChildrenRecursive<Property>();
        foreach (var prop in cmdLine)
        {
            if (prop.Name == "Sources" || prop.Name == "CommandLineArguments")
                Console.WriteLine($"    {prop.Name}: {prop.Value?.Substring(0, Math.Min(200, prop.Value.Length))}");
        }
    }
}

// Check for MSB4181 or other cascading errors
Console.WriteLine("\n=== SEARCHING FOR CASCADE INDICATORS ===");
var allMessages = log.FindChildrenRecursive<AbstractDiagnostic>();
foreach (var m in allMessages)
{
    if (m is Error err)
    {
        var parentProject = err.GetNearestParent<Project>();
        Console.WriteLine($"  Error in project '{parentProject?.Name}': {err.Code} - {err.Text}");
    }
}
EOF
