        Console.WriteLine($"  Csc in project: {t.Parent?.Parent}");
        var cmdLine = t.FindChildrenRecursive<Property>();
        foreach (var prop in cmdLine)
        {
            if (prop.Name == "Sources" || prop.Name == "CommandLineArguments")
                Console.WriteLine($"    {prop.Name}: {prop.Value?.Substring(0, Math.Min(200, prop.Value.Length))}");
